import java.util.Scanner;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Ensuring that the buffer size matches or exceeds the input length
        int bufferSize = Math.min(name.length(), 10);

        char[] buffer = new char[bufferSize];

        // Copying user input into the buffer with bounds checking
        name.getChars(0, bufferSize, buffer, 0);

        System.out.println("Hello, " + String.valueOf(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
